#include<bits/stdc++.h>
using namespace std;
int main(void){
	int n,a[1000005],b[1000005],s=0,q=0;
	cin>>n;
	for(int i=0;i<n;i++)cin>>a[i];
	for(int i=0;i<n;i++)cin>>b[i];
	for(int i=0;i<n;i++){
		s+=a[i]>b[i],q+=b[i]>a[i];
	}
	cout<<s<<' '<<q<<"\n";
	if(s>q)cout<<"S";
	else if(q>s)cout<<"Q";
	else cout<<"Tie";
	return false;
}
